// TestimonialCard.jsx
import React, { useState } from "react";

const TestimonialCard = ({ card }) => {
  const [flipped, setFlipped] = useState(false);

  const toggleFlip = () => setFlipped(!flipped);

  return (
    <div
      className="w-80 h-96 perspective-1000 cursor-pointer mx-4"
      onClick={toggleFlip}
      role="button"
      tabIndex={0}
      onKeyPress={(e) => e.key === "Enter" && toggleFlip()}
      aria-label={`Card de ${card.title}, click para girar`}
    >
      <div 
        className={`relative w-full h-full rounded-2xl transition-transform duration-500 transform-style-preserve-3d shadow-lg bg-primary text-surface-elevated select-none ${
          flipped ? 'rotate-y-180' : 'rotate-y-0'
        }`}
      >
        {/* Frente */}
        <div className="absolute w-full h-full rounded-2xl backface-hidden flex flex-col justify-center items-center p-8 text-center">
          <h3 className="text-2xl font-bodoni font-bold mb-6 text-surface-elevated uppercase tracking-wider select-none">
            {card.title}
          </h3>
          <p className="text-base font-miles leading-relaxed mb-8 break-words">
            {card.text}
          </p>
          <div className="font-bodoni font-bold text-xl select-none">
            {card.role}
          </div>
        </div>

        {/* Reverso */}
        <div className="absolute w-full h-full rounded-2xl backface-hidden flex flex-col justify-center items-center p-6 text-center transform rotate-y-180 overflow-y-hidden">
          {card.backType === "list" ? (
            <ul className="list-none p-0 m-0 w-fit text-surface-elevated text-center select-none">
              {card.backContent.map((item, i) => (
                <li key={i} className="text-lg my-1 font-miles">
                  {item}
                </li>
              ))}
            </ul>
          ) : (
            <img
              src={card.backContent}
              alt={`Imagen de ${card.title}`}
              className="w-[90%] h-[80%] rounded-full object-cover select-none mx-auto block"
              draggable={false}
            />
          )}
        </div>
      </div>
    </div>
  );
};

export default TestimonialCard;
